func (p *Pool) worker(ctx context.Context) {
    defer p.wg.Done()
    for {
        select {
        case <-ctx.Done():
            return
        case job, ok := <-p.jobs:
            if !ok {
                return
            }
            func() {
                defer func() {
                    if r := recover(); r != nil {
                        p.logger.Error("worker panic", "recover", r)
                    }
                }()
                if err := job(ctx); err != nil {
                    p.logger.Error("job error", "err", err)
                }
            }()
        }
    }
}

// errgroup + semaphore: parallel IO with bounded concurrency, fail-fast on first error.
func ProcessAll[T any, R any](
    ctx context.Context, items []T, concurrency int64,
    fn func(context.Context, T) (R, error),
) ([]R, error) {
    results := make([]R, len(items))
    sem := semaphore.NewWeighted(concurrency)
    g, gctx := errgroup.WithContext(ctx)

    for i, it := range items {
        i, it := i, it // capture (pre-Go 1.22)
        if err := sem.Acquire(gctx, 1); err != nil {
            return nil, err
        }
        g.Go(func() error {
            defer sem.Release(1)
            r, err := fn(gctx, it)
            if err != nil {
                return err
            }
            results[i] = r
            return nil
        })
    }
    if err := g.Wait(); err != nil {
        return nil, err
    }
    return results, nil
}
